mpatible development board with a built in Qwiic connector, eliminating the need … $21.95 SparkFun Micro OLED Breakout (Qwiic) LCD-22495 The SparkFun Qwiic Micro OLED Breakout is a Qwiic enabled version of our popular MicroView and micro OLED display! $11.25 SparkFun Qwiic Soil Moisture Sensor SEN-24409 A simple breakout for measuring the moisture in soil and similar materials. The exposed pads function together acting as a va… $6.95 9V Battery Holder PRT-10512 This 9V battery holder allows your battery to snap in tight and holds it in place, which is great in situations where you don… $3.95 9V Alkaline Battery PRT-10218 These are your standard 9 Volt alkaline batteries from Rayovac. Don't even think about trying to recharge these. Use them wit… $2.50 Hardware Setup The hardware setup for this project is super straightforward. Attach the Qwiic Soil Moisture Sensor to the Qwiic OLED via a Qwiic Cable and then attach the OLED to the Redboard. We used a 9V battery and 9V battery holder to power this project so that we could keep it portable, but you could use a portable charger or hook it up straight to your computer depending on your use case and availability of parts on hand. We also used some screws and a 3D-printed base plate to keep the display and sensor together, but that is also not necessary. So simple! Calibration System Calibration
To get any sort of useful data out of your Soil Moisture Sensor, it is advised that you calibrate it to whatever soil you plan to monitor. Different types of soil can affect the sensor, and you may get different readings from one composition tot he next. Before you start storing moisture data or triggering events based on that value, you should see what values you are actually getting from your sensor. Using the sketch above, note what values your sensor outputs when the sensor is completely dry vs when the sensor is completely submerged in a shallow cup of water. Depending on what microcontoller you're using, the operating voltage of that microcontoller, and the resolution of its analog-to-digital converter, you're results will vary. For example, using the same circuit above, if I detach the VCC pin from D7 and attach it directly to the 5V supply on the RedBoard, you'll see the close to the following values in the serial monitor when the sensor is dry (~0) and when it is completely saturated with moisture (~880). Code The code for this project is really simple, just download the Arduino libraries for the products used and past the code below into the terminal! Make sure to adjust the moisture values to suit your plant's needs. The values used below seem to work pretty well for my money tree, which is a pretty low-fuss plant. #include <Wire.h>
#include <SparkFun_Qwiic_OLED.h>
#include <res/qw_fnt_5x7.h>

QwiicMicroOLED myOLED;

#define COMMAND_GET_VALUE   0x05
const uint8_t qwiicAddress = 0x28;
uint16_t ADC_VALUE = 0;


const int dryValue = 1023;
const int wetValue = 400;

void setup() {
    Serial.begin(115200);
    Wire.begin();

    while (myOLED.begin() == false) {
        Serial.println("OLED not connected, check wiring!");
        delay(1000);
    }

    testForConnectivity();
}

void loop() {
    int moistureValue = getMoisture();
    displayMoisture(moistureValue);
    delay(1000);
}

int getMoisture() {
    get_value();
    return map(ADC_VALUE, dryValue, wetValue, 0, 100);
}

void get_value() {
    Wire.beginTransmission(qwiicAddress);
    Wire.write(COMMAND_GET_VALUE);
    Wire.endTransmission();

    Wire.requestFrom((uint8_t)qwiicAddress, (uint8_t)2);

    if (Wire.available() >= 2) {
        uint8_t ADC_VALUE_L = Wire.read();
        uint8_t ADC_VALUE_H = Wire.read();
        ADC_VALUE = (ADC_VALUE_H << 8) | ADC_VALUE_L;
    }
}

void displayMoisture(int moistureValue) {
    myOLED.erase();

    if (moistureValue < 30) {
        // Happy Face when well-watered
        myOLED.line(20, 0, 30, 0);   // Left eye
        myOLED.line(40, 0, 50, 0);   // Right eye

        // Smile: \__/
        myOLED.line(20, 20, 30, 10);   // Left smile
        myOLED.line(30, 10, 40, 10);   // Bottom of smile
        myOLED.line(40, 10, 50, 20);   // Right smile
    } else if (moistureValue >= 50 && moistureValue < 70) {
        // Neutral Face
        myOLED.line(20, 0, 30, 0);   // Left eye
        myOLED.line(40, 0, 50, 0);   // Right eye
        myOLED.line(20, 20, 50, 20);   // Neutral line
    } else {
        // Sad Face when dry
        myOLED.line(20, 0, 30, 0);   // Left eye
        myOLED.line(40, 0, 50, 0);   // Right eye

        // Sad mouth: /--\
        myOLED.line(20, 10, 30, 20);   // Left sad
        myOLED.line(30, 20, 40, 20);   // Bottom of sad
        myOLED.line(40, 20, 50, 10);   // Right sad
    }

    myOLED.display();

    Serial.print("Moisture: ");
    Serial.print(moistureValue);
    Serial.println("%");
}

void testForConnectivity() {
    Wire.beginTransmission(qwiicAddress);
    if (Wire.endTransmission() != 0) {
        Serial.println("Check connections. No soil sensor found.");
        while (1);
    }
} Share Use this URL to share: Share on Tumblr Submit to reddi Share on Twitter Share on Facebook Pin It Sections Introduction Materials Hardware Setup Calibration Code Comments 0 View Paginated Print Tags Qwiic License Creative Commons tutorials are CC BY-SA 4.0 About SparkFun Read Our Story Press & Media SparkFun Education Job Openings Partner With Us See Our Partners View Our Services Become a Distributor/Reseller Receive Volume Discounts Support Customer Support Purchase Order & Payment Terms Technical Assistance FAQs Site Information Terms Of Service Privacy Policy Compliance Site Map Subscribe View Our Social Channels YouTube Instagram GitHub Facebook Twitter RSS TikTok SparkFun Electronics ® / 6333 Dry Creek Parkway, Niwot, CO 80503

Professional EDU Distributor Customer Support Shop Documentation News Today's Deals Community SparkX SparkFun Electronics - sparkfun.com search documentation Back to Webstore My Account My Account Featured Products GPS/GNSS Sensors Development Boards IoT & Wireless Components Kits Shop All Product Categories Navigation menu Menu Account Featured Products GPS/GNSS Sensors Development Boards IoT & Wireless Components Kits Shop All Product Categories Shop Documentation News Today's Deals Community SparkX Home Tutorials Qwiic & Easy DIY Ambient Light Indicator Qwiic & Easy DIY Ambient Light Indicator ≡ Pages Contributors: -KJB- Share Use this URL to share: Share on Tumblr Submit to reddi Share on Twitter Share on Facebook Pin It Introduction In this tutorial, we’ll walk through how to use the SparkFun Ambient Light Sensor - VEML7700 (Qwiic) to accurately detect the brightness of your surroundings. This sensor measures light intensity in lux, giving output values that closely match human eye sensitivity from very dim to direct sunlight. With its easy I²C Qwiic connection, the VEML7700 makes it simple to integrate ambient light sensing into your projects for display dimming, energy-efficient lighting systems, or environmental data logging. SparkFun Ambient Light Sensor - VEML7700 (Qwiic) SEN-29211 The SparkFun Qwiic VEML7700 Ambient Light Sensor delivers precise 16-bit lux readings via I2C, featuring Arduino and Python l… $6.95 If you are looking for the full Hookup Guide for the SparkFun Ambient Light Sensor - VEML7700 Qwiic, click the button bellow. This guide only covers a simple project to get you started quickly, while the full Hookup Guide goes over every detail of the sensor. View the Full Hookup Guide Hardware Needed For this project, you'll need: SparkFun RedBoard Qwiic SparkFun Ambient Light Sensor (VEML7700) SparkFun Qwiic Button - Green LED Qwiic cables - 2x USB cable to connect RedBoard → computer Software Setup Getting Started with the Arduino IDE This guide assumes users are utilizing the latest version of the Arduino IDE on your desktop. If this is your first time using Arduino IDE, library, or board add-on, please review the following tutorials: Installing the Arduino IDE Installing an Arduino Library Installing Board Definitions in the Arduino IDE Installing the Required Libraries and Sketch Install the SparkFun_Qwiic_Button and SparkFun_VEML7700_Arduino_Library : Open the Arduino IDE and navigate to Sketch > Include Library > Manage Libraries . In the Library Manager, search for "SparkFun Qwiic Button and Sparkfun VEML7700" and install the latest versions of each from SparkFun. You can now copy and paste the code below into a fresh Arduino sketch: #include <Wire.h>
#include <SparkFun_Qwiic_Button.h>
#include <SparkFun_VEML7700_Arduino_Library.h>

QwiicButton button;
VEML7700 lightSensor;

void setup() {
    Serial.begin(115200);
    Wire.begin();

    // Initialize the button
    if (!button.begin()) {
        Serial.println("Button not found!");
        while (1);
    }
    Serial.println("Button found.");

    // Initialize the ambient light sensor
    if (!lightSensor.begin()) {
        Serial.println("Light sensor not found!");
        while (1);
    }
    Serial.println("Light sensor found.");

    button.LEDon(0); // Start with LED on, but low brightness
}

void loop() {
    // Check if button is pressed
    if (button.isPressed()) {
        // If pressed, turn off LED regardless of light
        button.LEDoff();
        Serial.println("Button pressed, LED off.");

        // Wait until released
        while (button.isPressed()) {
            delay(10);
        }

        Serial.println("Button released.");
    } else {
        // Read light level
        float lux = lightSensor.getLux();

        // Clamp lux to a usable range (0 to 400 for mapping)
        if (lux > 400) lux = 400;
        if (lux < 0) lux = 0;

        // Invert lux to brightness: lower light → higher brightness (0–255)
        uint8_t brightness = map(lux, 0, 400, 255, 0);

        // Apply brightness to LED
        button.LEDon(brightness);

        Serial.print("Lux: ");
        Serial.print(lux); Once you have the sketch and libraries installed, you can upload the code to your development board. After uploading, the Qwiic button will be fully lit when the room is dark and will turn off when there is enough light. To adjust how sensitive the brightness control is, you can change the value 400 to any number between 100 and 1000. This number sets the light threshold needed to turn the button on or off. Need Help? If you need technical assistance or more information on a product that is not working as you expected, we recommend heading over to the SparkFun Technical Assistance page for some initial troubleshooting. SparkFun Technical Assistance Page If you can't find what you need there, the SparkFun Forums is a great place to search product forums and ask questions. Account Registration Required: If this is your first visit to our forum, you'll need to create a Forum Account to post questions. Conclusion You’ve successfully set up the SparkFun Ambient Light Sensor - VEML7700 (Qwiic) to detect and measure the brightness of a room. This tutorial provided the foundational steps for connecting, configuring, and reading lux values from the sensor. With this setup in place, you can now build on this knowledge to develop projects like automatic brightness adjustment, smart lighting, or environmental monitoring. Watch how it works here: Share Use this URL to share: Share on Tumblr Submit to reddi Share on Twitter Share on Facebook Pin It Sections Introduction Hardware Needed Software Setup Installing the Required Libraries and Sketch Conclusion Comments 0 View Paginated Print Tags License Creative Commons tutorials are CC BY-SA 4.0 About SparkFun Read Our Story Press & Media SparkFun Education Job Openings Partner With Us See Our Partners View Our Services Become a Distributor/Reseller Receive Volume Discounts Support Customer Support Purchase Order & Payment Terms Technical Assistance FAQs Site Information Terms Of Service Privacy Policy Compliance Site Map Subscribe View Our Social Channels YouTube Instagram GitHub Facebook Twitter RSS TikTok SparkFun Electronics ® / 6333 Dry Creek Parkway, Niwot, CO 80503

Introduction Shrimp farming relies on maintaining optimal water quality, but traditional monitoring methods are inefficient, labor-intensive, and prone to inaccuracies. Farmers typically rely on manual sampling and periodic testing, which fail to capture sudden fluctuations in key parameters such as temperature, pH, turbidity, dissolved oxygen, and total dissolved solids (TDS). These fluctuations can quickly lead to shrimp stress, disease outbreaks, and mass mortality, significantly impacting productivity and profitability. Furthermore, many shrimp farms are located in remote areas where Wi-Fi connectivity is unreliable or unavailable, making real-time monitoring and remote data access challenging. Existing solutions often require expensive infrastructure, frequent maintenance, and complex calibration processes, limiting their practicality for small and medium-scale farmers. Without an automated, real-time monitoring system , farmers are unable to detect water quality issues early enough to take corrective action. This lack of timely intervention leads to higher operational costs, increased shrimp mortality rates, and reduced overall yield. There is a critical need for a cost-effective, real-time, and low-maintenance monitoring solution that ensures continuous data collection, instant alerts, and seamless remote access for improved farm management. To address these challenges, we developed the Smart Shrimp Monitoring Buoy powered by a Particle B-SoM , designed for real-time, automated water quality monitoring in remote aquaculture environments. The buoy continuously measures temperature, pH, turbidity, dissolved oxygen (DO), and total dissolved solids (TDS) using high-precision sensors. The B-SoM module ensures reliable cellular connectivity , enabling farmers to access live water quality data remotely, even in areas without Wi-Fi coverage. Key features of our solution include: Real-time monitoring: The system collects and transmits water quality data at regular intervals, allowing farmers to respond quickly to critical changes. Automated alerts: When parameters exceed safe thresholds, farmers receive instant notifications, enabling immediate corrective action. Solar-powered operation: The buoy is equipped with 6V solar panels and a DFRobot solar charge controller , ensuring continuous operation without frequent maintenance. Rugged and low-maintenance design: The waterproof, floating buoy is built to withstand harsh aquatic conditions while minimizing maintenance efforts. Scalability and affordability: The system is designed to be cost-effective and easily scalable, making it accessible to shrimp farmers of all sizes. By providing automated, real-time, and remote water quality monitoring , our solution reduces shrimp mortality, improves farm productivity, and minimizes operational costs , leading to more sustainable and profitable shrimp farming. B524 SoM The B-SoM is the cornerstone of this shrimp monitoring project, functioning as a dependable IoT module for cellular connectivity. Built on the Particle IoT platform, it comes equipped with a free global embedded SIM card and data plan. To interface with the module, we utilize the M.2 SoM Evaluation Board, a user-friendly breakout board that provides access to the B-SoM’s essential pins and functionalities. This facilitates smooth development and deployment within our shrimp monitoring system. The evaluation board includes a variety of features, such as USB ports for both the nRF52840 MCU and the cellular modem, an SD card connector, an Ethernet connector, a barrel jack power connector, buttons, an RGB LED, a charge status LED, and a connector for a LiPo battery. These components collectively enhance the board’s versatility and ease of use in the project. For a quick start with the BSoM read this tutorial . To utilize the full capabilities of the B524 SoM with the Particle platform, you’ll need to set up your Particle account and configure your device. Follow the steps here to get started. LM35 temperature sensor The LM35 sensor measures water temperature, which is essential for maintaining proper shrimp metabolism and health. Shrimp are highly sensitive to temperature changes, so monitoring and maintaining a stable temperature range helps improve growth and survival rates. We are using the waterproof version of the temperature sensor. The sensor operates by generating an analog voltage proportional to temperature, providing a simple and accurate method for temperature measurement. Here is the sample code for getting temperature from lm35 and will print in the Serial monitor. #define TEMP_PIN A0 

void setup() {
    Serial.begin(9600);
}

void loop() {
    int sensorValue = analogRead(TEMP_PIN);
    float voltage = sensorValue * (3.3 / 4095.0);
    float temperatureC = voltage * 100.0; // LM35 gives 10mV per degree Celsius
    Serial.println("Temperature: " + String(temperatureC) + "°C");
    delay(1000);
} pH sensor The pH sensor is used to measure water acidity or alkalinity, which is crucial for creating an optimal environment for shrimp. It operates by detecting the voltage difference caused by hydrogen ion activity in the solution. This sensor is factory-calibrated, eliminating the need for additional calibration. In shrimp farming, maintaining a pH level between 6.5 and 8.5 is essential for promoting growth, ensuring proper oxygen availability, and minimizing ammonia toxicity. Its plug-and-play design and compatibility with microcontrollers make it user-friendly for both beginners and professionals. Additionally, the use of the DFRobot pH library simplifies data processing, ensuring accurate and reliable pH readings for the project. // Sample code for getting pH values

#include "DFRobot_ESP_PH.h"
#include <EEPROM.h>

#define PH_PIN A1
DFRobot_ESP_PH ph;

float voltage, phValue, temperature = 25.0;  // Default temperature

void setup() {
    Serial.begin(9600);
    ph.begin();
}

void loop() {
    int sensorValue = analogRead(PH_PIN);
    voltage = sensorValue * (3.3 / 4095.0);  // Convert analog reading to voltage
    phValue = ph.readPH(voltage, temperature);  // Get pH value using library function

    Serial.print("pH: ");
    Serial.println(phValue);

    delay(1000);
} Turbidity sensor The turbidity sensor measures water clarity by detecting the amount of light scattered by suspended particles in the water. High turbidity reduces light penetration, limiting photosynthesis in aquatic plants and decreasing oxygen production. Excessive suspended particles can clog shrimp gills, causing stress and making them more vulnerable to diseases. Poor water clarity also affects shrimp feeding behavior, as they rely on visual cues to locate food. Additionally, high turbidity often indicates organic matter buildup, which can lead to harmful bacterial growth and deteriorate water quality. Monitoring turbidity levels helps farmers take timely actions, such as adjusting aeration or filtration, to maintain a healthy environment for shrimp. // Sample code for getting Turbidity Values

#define SensorPin A0
#define VREF 3.3  // Adjust for Particle devices (3.3V reference)

float volt;
float ntu;

void setup() {
    Serial.begin(115200);
    pinMode(SensorPin, INPUT);
}

void loop() {
    volt = 0;
    for (int i = 0; i < 800; i++) {
        volt += ((float)analogRead(SensorPin) / 4095) * VREF; // Adjust for 12-bit ADC
    }
    volt = volt / 800;
    volt = round_to_dp(volt, 2);
   
    // Map voltage to the required range
    volt = mapf(volt, 0.0, 3.3, 1.83, 3.68);
   
    // Calculate NTU using the quadratic equation
    ntu = 493.17 * pow(volt, 2) - 3749.1 * volt + 7152.3;
   
    // Limit NTU values between 0 and 2000
    if (ntu < 0) {
        ntu = 0;
    } else if (ntu > 2000) {
        ntu = 2000;
    }
   
    Serial.print("Voltage: ");
    Serial.print(volt);
    Serial.println(" V");
   
    Serial.print("Turbidity: ");
    Serial.print(ntu);
    Serial.println(" NTU");
   
    delay(1000);
}

float round_to_dp(float in_value, int decimal_place) {
    float multiplier = powf(10.0f, decimal_place);
    in_value = roundf(in_value * multiplier) / multiplier;
    return in_value;
}

float mapf(float x, float in_min, float in_max, float out_min, float out_max) {
    return (x - in_min) * (out_max - out_min) / (in_max - in_min) + out_min;
} The code reads analog voltage from the turbidity sensor 800 times and converts it into a calibrated voltage value. This voltage is then used in a formula to calculate turbidity (NTU), ensuring values stay within the 0–2000 range. Finally, the voltage and NTU values are displayed on the Serial Monitor to help monitor water clarity. TDS sensor The TDS sensor measures dissolved solids and salinity by detecting the electrical conductivity of the water. Higher conductivity indicates a higher concentration of dissolved minerals, salts, and organic matter, which directly impacts shrimp health and growth. Excessive TDS levels can cause osmotic stress in shrimp, affecting their ability to regulate water and salt balance. Poor water quality with high dissolved solids can also lead to gill irritation, reduced oxygen uptake, and increased susceptibility to diseases. Conversely, low TDS levels may indicate a lack of essential minerals needed for shrimp development. Regular monitoring of TDS levels helps maintain optimal water conditions, ensuring a balanced environment for healthy shrimp farming. // Sample code for getting TDS value

#include <math.h>

#define TDS_PIN A2
#define VREF 3.3   // Reference voltage for B SoM (3.3V)
#define TDS_FACTOR 0.5  // Conversion factor for TDS

void setup() {
    Serial.begin(9600);
    pinMode(TDS_PIN, INPUT);
}

void loop() {
    int rawValue = analogRead(TDS_PIN);  // Read sensor output
    float voltage = rawValue * (VREF / 1024.0);  // Convert to voltage
    float ecValue = (133.42 * voltage * voltage * voltage - 255.86 * voltage * voltage + 857.39 * voltage) * 0.01; 
    float tdsValue = ecValue * TDS_FACTOR;  // Convert EC to TDS

    Serial.println("TDS: " + String(tdsValue) + " ppm");
    delay(1000);
} Dissolved oxygen sensor Dissolved oxygen refers to the extent of free, non-compound oxygen present in water or other liquids. It’s one of the most important parameters when assessing water quality due to its influence on the organisms living within a body of water. A DO level that’s too high or too low can harm aquatic life and affect water quality. The dissolved oxygen sensor measures the concentration of oxygen in water using an electrochemical or optical method. It helps ensure sufficient oxygen levels for shrimp respiration. There are three types of dissolved oxygen sensor measurements: galvanic, polarographic, and optical. We are using the galvanic dissolved oxygen sensor for this project due to its reliability and simplicity. Before getting the dissolved oxygen sensor probe to work, we need to prepare the probe. To prepare the probe, you need to dissolve approximately 4 grams of KCL crystals in 52 grams of water to create a 7.5% KCL solution . Preparation includes adding 7.5% KCL solution into the membrane cap, ensuring the membrane is wrinkle-free, filling 2/3 of the cap with KCL, and securing the cap to eliminate air bubbles. The electrode tube should be free of air bubbles to prevent reading fluctuations. For detailed instructions, visit Dissolved Oxygen Probe Preparation. We are using single-point calibration, which involves calibrating the saturated dissolved oxygen at a fixed temperature, suitable for stable temperature environments. Use an LM35 temperature sensor to measure the temperature of the liquid and note down the value in °C. Next, wet the DO probe in the same liquid and gently shake off any excess water droplets to ensure the probe membrane is clean and hydrated. Then, expose the probe to air while maintaining natural airflow around it (avoid using a fan or artificial airflow). Wait for the output voltage from the DO probe to stabilize, and once stable, record the voltage. This voltage represents the saturated dissolved oxygen voltage at the current temperature. Use this recorded voltage value in your final code for calibration, as it corresponds to 100% dissolved oxygen saturation at the measured temperature. // Code to get the reference voltage

#include <Arduino.h>

#define VREF 5000 //VREF(mv)
#define ADC_RES 1024 //ADC Resolution
uint32_t raw;
void setup() {
  Serial.begin(9600);
}
void loop() {
  raw = analogRead(A1);
  Serial.println("raw:\t" + String(raw) + "\tVoltage(mv)" + String(raw * VREF / ADC_RES));
  delay(1000);
}
// Code to get the DO value in mg/L

#include <Arduino.h>
 // Pin and constants
#define DO_PIN A1 // Analog pin for DO sensor
#define VREF 3300 // Reference voltage in mV
#define ADC_RES 4096 // 12-bit ADC resolution

#define TWO_POINT_CALIBRATION 0

#define READ_TEMP(25) // Current water temperature (°C)

// Single-point calibration values ( Here we are using Single Point calibration)
#define CAL1_V(1455) // Calibration voltage at CAL1_T (mV)
#define CAL1_T(25) // Calibration temperature (°C)

//Two-point calibration needs to be filled CAL2_V and CAL2_T
#define CAL2_V(1300) //mv
#define CAL2_T(15) //℃

// DO lookup table (saturation values from 0°C to 40°C)
const uint16_t DO_Table[41] =
{
14460, 14220, 13820, 13440, 13090, 12740, 12420, 12110, 11810, 11530,
11260, 11010, 10770, 10530, 10300, 10080, 9860, 9660, 9460, 9270,
9080, 8900, 8730, 8570, 8410, 8250, 8110, 7960, 7820, 7690,
7560, 7430, 7300, 7180, 7070, 6950, 6840, 6730, 6630, 6530, 6410
};

uint8_t Temperaturet;
uint16_t ADC_Raw, ADC_Voltage, DO;

// DO calculation using calibration
int16_t readDO(uint32_t voltage_mv, uint8_t temperature_c) {
  #if TWO_POINT_CALIBRATION == 0
  uint16_t V_saturation = (uint32_t) CAL1_V + 35 * temperature_c - CAL1_T * 35;
  return (voltage_mv * DO_Table[temperature_c]) / V_saturation;
  #else
  uint16_t V_saturation = ((temperature_c - CAL2_T) * (CAL1_V - CAL2_V)) / (CAL1_T - CAL2_T) + CAL2_V;
  return (voltage_mv * DO_Table[temperature_c]) / V_saturation;
  #endif
}
void setup() {
  Serial.begin(9600);
}
void loop() {
  Temperaturet = (uint8_t) READ_TEMP;
  ADC_Raw = analogRead(DO_PIN);
  ADC_Voltage = (uint32_t) VREF * ADC_Raw / ADC_RES;
  DO = readDO(ADC_Voltage, Temperaturet);
  Serial.print("Temp:\t" + String(Temperaturet) + "\t");
  Serial.print("ADC:\t" + String(ADC_Raw) + "\t");
  Serial.print("Volt:\t" + String(ADC_Voltage) + "mV\t");
  Serial.println("DO:\t" + String(DO));
  delay(1000);
} Rain sensor The rain sensor detects precipitation levels by measuring changes in electrical resistance when water droplets land on its conductive grid. This data helps monitor rainfall intensity and its impact on shrimp farming conditions. Rain can cause sudden temperature drops, stressing shrimp and slowing their growth. It also lowers pH levels, dilutes essential minerals, and reduces salinity, making the water less suitable for shrimp. Heavy rainfall increases turbidity by washing debris into the pond, which decreases oxygen levels and affects shrimp health. By using a rain sensor, farmers can receive real-time alerts and take preventive measures to maintain optimal water quality. // Code to detect rain

#include <Arduino.h>

#define RAIN_SENSOR_PIN A4  // Define the pin for the rain sensor

void setup() {
    Serial.begin(115200);
}

void loop() {
    static unsigned long timepoint = millis();
    if (millis() - timepoint > 1000U) {  // Every 1 second
        timepoint = millis();

        // Read Rain Sensor
        int rainValue = analogRead(RAIN_SENSOR_PIN);
        bool isRaining = rainValue < 1000; // Adjust threshold based on sensor readings

        // Serial Print
        Serial.print("Rain Sensor Value: "); Serial.print(rainValue);
        Serial.print(" | Rain Detected: "); Serial.println(isRaining ? "Yes" : "No");
    }
} Power management The system is powered by six solar panels (6V each) connected in parallel to increase current. The panels are wired to the 5V Solar Power Manager , which regulates the power flow to the 1800mAh battery . This battery stores energy and provides stable power for night or cloudy conditions. The Dissolved oxygen sensor needs 9V to operate, to compensate the voltage we have used the LM2596S Buck converter power supply. Antenna To enhance cellular connectivity and ensure stable data transmission in remote or aquatic locations, we upgraded the default antenna to a rubber duck antenna for use with the Particle B-SoM. This antenna features a durable, flexible exterior and connects via a standard SMA connector, offering omnidirectional radiation that’s ideal for buoy-based systems, which may shift due to wind or water currents. To connect the antenna to the B-SoM’s U.FL port, we used a 15cm U.FL to SMA female bulkhead RF cable assembly. Operating across a wide frequency range (698–960 MHz and 1710–2690 MHz) with up to 5 dBi gain, the rubber duck antenna significantly improves performance in low-signal areas compared to embedded or PCB antennas. The sleek form factor also adds a more professional, rugged aesthetic to the final device, making it suitable for both field and demonstration use. 3D model We designed a custom 3D model with a trapezoidal body and a circular semi-spherical base to function as a floating buoy. This distinctive shape enhances balance and stability on the water surface while offering ample room to mount sensors and securely enclose the electronics. The full structure comprises three main parts: the upper trapezoidal section, the semi-spherical middle, and a flat circular base for holding internal components. The trapezoidal and semi-spherical parts were 3D printed using PLA, chosen for its lightweight, water-resistant, and outdoor-friendly properties. For saving the time and the filament the base was laser-cut from 2mm yellow acrylic. Assembly Before getting into the assembly, we finalized the  code and the circuit using a  breadboard and jumpers. First, we secured the sensors on their corresponding slots. Next, we secure the sensors breakout boards on the one side of acrylic and remaining on the other side. Then, we attached the solar panels and the rain sensor. After that, we fixed the three parts with the M3 nuts and bolts. Once complete, here is what the final version looked like. Ubidots dashboard We used Ubidots to visualize real-time sensor data from the buoy. The Particle B-SoM sends temperature, pH, turbidity, dissolved oxygen, TDS, and rain sensor data to the Ubidots platform using webhooks. Ubidots provides a clean, user-friendly dashboard where each parameter can be monitored through graphs, gauges, and indicators. Interconnecting Particle Cloud with Ubidots Create an account at ubidots.com. Create a new device and note the device label . In the Particle console, go to Integrations > New Integration > Ubidots . Set the event name and paste the Ubidots API endpoint: https://industrial.api.ubidots.com/api/v1.6/devices/{device-label} Use the POST method and include your Ubidots Token in the header. Format your JSON body with the variable labels and values as { 
  "temperature": "{{{temperature}}}",
  "ph": "{{{ph}}}", 
  "turbidity": "{{{turbidity}}}",
  "do": "{{{do}}}", 
  "tds": "{{{tds}}}", 
  "rain": "{{{rain}}}"
} Once configured, data from the buoy will appear in Ubidots and can be customized into a real-time monitoring dashboard. Sending alerts with Ubidots To create alerts, navigate to Data > Events , and then “Create Event . ” In the Triggers section: Click “Add Variable.” Select your device and variable Set condition: “is greater than” for upper limit “is less than” for lower limit Enter the threshold value In the Action section: Click “Add Action.” Select “Send SMS.” Enter the recipient’s phone number (e.g., +1234567890) Type the SMS message ( Hi there, {{Variable name}} was {{Trigger value}} at {{Trigger timestamp}} ) In the Settings section, name your event (e.g., “Temperature High Alert”) Click “Save.” Test by sending a value that triggers the condition. Once everything is configured, you get alerts like this when the values cross the thresholds. What does this offer The Smart Shrimp Monitoring Buoy offers a practical and impactful solution to the challenges of traditional shrimp farming by enabling real-time, automated water quality monitoring — especially in remote, low-connectivity environments. By reducing shrimp mortality, improving yield, and minimizing manual labor, it empowers farmers with timely insights and greater control over their operations. Looking ahead, future improvements could include integrating predictive analytics and AI-driven insights to anticipate harmful trends before they occur, expanding sensor support for additional parameters like ammonia and nitrate, and developing a companion mobile app for even more accessible monitoring. By continuing to enhance functionality and ease of use, this system can further revolutionize sustainable aquaculture practices and support smarter farming at scale. Assets for replication You can find all the necessary resources and assets required to replicate this project in the GitHub repository .

The problem Few things in life are more annoying than trying and failing to find a parking spot, especially in a parking garage. Nobody wants to spend their time circling the garage waiting for someone to leave. It’s dreadfully boring and bad for the environment to boot! Parking management is essential in smart buildings for enhancing efficiency, convenience, and sustainability. However, most parking management systems are clunky, outdated and expensive. The solution In this project, we will build our own smart parking systems using sensors and IoT technology to reduce the time it takes to find a parking spot. Monitoring the occupancy rating and the related patterns, we will optimize space usage and improve the overall experience for employees or tenants in using the available parking space. Bill of materials M524 SoM and M.2 SoM Evaluation Board 12V optical distance sensor 12V LED beacon SX1509 16 Output I/O Expander 12V power supply Optocouplers Colored 24 AWG wire – red, black, green, blue, white Enclosure for the M-SoM Various mechanical components to mount the enclosure in the designated place Required skills and tools Skills Arduino programming Crimping, soldering and connector assembly Basic mechanical assembly skills Tools PC Crimping tool Soldering iron Multimeter Set of screwdrivers Developing a parking management system based on the M-SoM System design Our parking system uses the M524 SoM and the M.2 SoM Evaluation Board to create a smart, efficient solution. Here’s how it works: We place sensors in each parking spot to detect when a car is parked there. The M524 SoM collects this data from all the sensors. It then sends this information to the Particle Cloud, which is a secure online platform designed for IoT devices. The Particle Cloud processes and stores this data, making it easily accessible from anywhere. This means parking lot managers can see real-time occupancy data on their phones or computers. Each parking spot also has an LED beacon. When a car parks in a spot, the M524 SoM sends a signal through the Particle Cloud to turn on that spot’s LED beacon. Using the Particle Cloud offers several advantages. It allows for remote monitoring and control of the entire system. We can easily update the software on all devices at once. It also enables integration with other services, like mobile apps that could guide drivers to open spots. This system makes finding empty parking spots easier for drivers and helps parking lot managers use their space more effectively. It’s a great example of how the Particle ecosystem can solve real-world problems. Hardware selection The M524 SoM + M.2 SoM Evaluation Board The Particle M-SoM is a great starting point for developing IoT (Internet of Things) prototypes, especially when you’re building systems that need reliable connectivity. One of its standout features is its flexibility—it supports both cellular and Wi-Fi connections. Having multiple connectivity options ensures that the system stays functional even if one method fails. In critical applications, this level of redundancy can be crucial, offering peace of mind that the system will stay online no matter what. It’s important to remember that there are different versions of the M-SoM for different parts of the world. If you’re in Europe, you should use the M524. If you’re in the USA, you should use the M404. This is because different countries use different cell phone networks, and you need to make sure your device will work with the right one. Optical distance sensor An optical distance sensor works by sending out an invisible infrared beam from an emitter. When this beam hits an object, like a car, it bounces back to the sensor’s receiver (called a photodiode). The angle at which the beam returns changes based on how far away the object is, and the sensor processes this change in angle into a voltage signal. That signal is then used to calculate the distance to the object. The accuracy and range of these sensors can vary depending on the model and how they’re designed. Different sensors are made for different purposes. In this case, we’ve chosen a sensor specifically suited for detecting cars. It can measure distances up to 6 meters, which makes it a good fit for monitoring parking spots. Additionally, this sensor is built to withstand outdoor conditions, thanks to its durable, weather-resistant enclosure. This ensures it can keep working reliably even in harsh environments, making it a practical choice for parking management systems. Light indicator As the name implies, the light indicator turns on to signal when a parking spot is available and switches off when the spot is taken. This makes it easy for drivers to quickly spot open spaces. Additionally, the light indicator can also serve another purpose: helping drivers park more accurately. By using it to gauge how close a car is to a wall or another obstacle, it can signal when you’ve reached the optimal distance for parking. This adds an extra layer of convenience, especially in tight or crowded spaces where precise parking is important. 16 Output I/O Expander Breakout – SX1509 The 16 Output I/O Expander Breakout (SX1509) is a key component in making our parking system scalable. While the evaluation board already provides a good number of GPIO (General Purpose Input/Output) pins, it’s not enough when you’re dealing with a large parking lot that could have hundreds of spaces. To address this, we’ve chosen to use an I/O expander like the SX1509. The I/O expander allows us to significantly increase the number of devices (like sensors and lights) that can be controlled from the same system without needing to add more complex wiring or extra hardware. This makes it possible to manage larger parking areas while keeping the system’s design simple and efficient. By using this approach, we ensure that the system can grow and adapt as needed without losing performance, making it suitable for everything from small parking lots to large-scale implementations. Optocoupler The optocoupler is a handy solution for bridging the gap between the different voltage levels used by the M524 module and the optical distance sensor. The M524 operates with 3.3V logic, but the optical distance sensor outputs a higher voltage. While this might seem like an issue, it’s manageable because the sensor’s output is just a simple on/off (digital high or low) signal. The optocoupler resolves this by isolating the two circuits. It works with two main components: an LED and a photosensitive device, both housed together in a single package. When the LED inside the optocoupler lights up, it sends an infrared signal that is detected by the photosensitive part. This setup allows the signal to pass between the high-voltage and low-voltage circuits without any direct electrical connection between them. Essentially, it enables safe communication between parts of the system operating at different voltages, ensuring the system works smoothly without risking damage to sensitive components. Hardware setup Wiring When wiring the system, it’s important to take your time and ensure everything is connected properly. Use color-coded wires to keep track of where each connection goes, and label both ends of the wires for clarity. Before powering anything on, double-check all connections with a multimeter to avoid mistakes. The diagram has been created using WireViz , a tool used in professional environments to easily document cables, wiring harnesses and connector pinouts and present them in a human readable format. The diagram uses boxes to describe electronic components like connectors, evaluation boards, sensors and cables, while using colored lines to describe the wires used to connect them. Electronic components are named using lower case letters, for example: ”msom_eval_board” , “optocoupler_1”, and “12v_supply”, while upper case is used for naming cables like “OPTOCOUPLER_OUTPUT_1” and “POWER_CABLE”. The 12V supply(12v_supply) is connected to a power plug(power_plug) through a 3 wired cable(POWER_CABLE). From the 12V supply, there are two wires coming out, a red one and a black one, both of them splitting in 3. A red and black pair used to power the optical distance sensor, a pair used to power the M-SoM through a wire ending in a barrel jack, the remaining red wire is connected to the third pin of the second optocoupler and the remaining black wire is connected to the GND pin of the LED beacon. The SX1509 is connected through the I2C Grove connector to the M-SoM evaluation board. Due to the fact that they are using 12V logic, both the optical distance sensor and the LED beacon are interfaced with the SX1509 through optocouplers. To make it easier to understand, consider optocoupler_1 an “input” optocoupler, and optocoupler_2 an “output” optocoupler. The first optocoupler receives a signal from the D_OUT pin on the distance sensor on it’s first pin and outputs 3.3V(provided on its 3rd pin) to the D0 pin of the SX1509, while the second optocoupler waits for a 3V3 signal on it’s 1st pin from the D1 pin of the SX1509 and outputs 12V(provided on its 4th pin from the power supply) from its 3rd pin to the LED beacon. Deploying the hardware This system can be adapted for two main use cases: Large parking areas (e.g. commercial garages): In a large parking area, such as a multi-level garage or commercial lot, the system can use green lights to indicate available spots. These lights will help drivers quickly find an empty parking space without having to circle around. This can significantly reduce time spent searching for a spot and improve the flow of traffic in busy parking areas. Smaller or residential parking areas: In a smaller parking lot, like in a residential building where parking spots are already assigned, the system can serve a different purpose. Instead of signaling availability, the red light could be used to help drivers park more precisely. The light would turn on as the car approaches the wall or a designated boundary, helping the driver gauge when they’ve reached an optimal parking position. This is especially helpful in tighter parking spaces where precision matters. In both of these cases, the system doesn’t just operate locally. It also sends real-time data about the overall parking lot’s occupancy to the cloud. This allows for centralized monitoring and management of parking spaces, offering valuable insights into space usage and helping improve operational efficiency. Whether it’s for a large commercial lot or a smaller residential setup, this system can adapt to meet different needs while keeping everything connected to the cloud for tracking and analysis. Software setup Initial configuration Go to https://setup.particle.io/ and follow the guide to set up and claim your device. Now that the device shows up on the My Devices tab inside the Particle Console we can focus on how to program it. There are two methods to flash applications on the M-SoM. The easiest method that requires almost no setup is to use their excellent Web IDE where you can find official and community developed libraries, as detailed in the following article . However, we’ve opted for the second option, the Particle Workbench extension for Visual Studio Code. This great article goes in depth explaining all its features and how to use them. Automation rules One of the biggest advantages of the M-SoM is its array of external antennas coupled with its SIM card. This together with the seamless integration of cloud functionalities enables us to send update messages to the Events tab of the Particle Console. The following sample sets up the I/O extender to work with an array of optical distance sensors and LEDs. The M-SoM constantly queries the sensors for updates, if such an update is detected the state of the corresponding LED is changed indicating that the parking space is available or occupied. The board also sends a message to the cloud indicating the parking space number and its current state change. const byte SX1509_ADDRESS = 0x3E; // SX1509 I2C address
SX1509 expander;
int space_nr[PARKING_SPOTS] = {0}, state;

void setup() {
  Serial.begin(115200);
  if (expander.begin(SX1509_ADDRESS) == false) {
    Serial.println("Failed to communicate. Check wiring and address of SX1509.");
    while (1);
  }
  for (int pin = 0; pin < 2 * PARKING_SPOTS; pin += 2) {
    expander.pinMode(pin, INPUT); //Optical sensors
    expander.pinMode(pin + 1, OUTPUT); //Light indicators
  }
}

void loop() {
  for (int pin = 0; pin < 2 * PARKING_SPOTS; pin += 2) {
    state = expander.digitalRead(pin); //Read Optical sensor
    if (state != space_nr[pin]) {
      if (state == HIGH) {
      Particle.publish("busy", String::format("space nr. %d", space_nr));
      expander.digitalWrite(pin + 1, LOW); //Turn off light
  }
  else {
      Particle.publish("free", String::format("space nr. %d", space_nr));
      expander.digitalWrite(pin + 1, HIGH); //Turn on light
  }
    }
    space_nr[pin] = expander.digitalRead(pin);
  }
} Let’s dive into how this code works. 1. Define the SX1509 I/O Expander const byte SX1509_ADDRESS = 0x3E; // SX1509 I2C address

SX1509 expander;

int space_nr[PARKING_SPOTS] = {0}, state; SX1509_ADDRESS: This is the address used to communicate with the SX1509 I/O expander over a protocol called I2C. It’s like giving the expander a phone number so the M-SoM can talk to it. space_nr: An array to keep track of each parking space’s status (whether it’s occupied or not). state: This variable will store the current reading from the sensors for each parking spot. 2. Setup function (runs once at startup) void setup() {

  Serial.begin(115200);

  if (expander.begin(SX1509_ADDRESS) == false) {

    Serial.println("Failed to communicate. Check wiring and address of SX1509.");

    while (1);

  }

  for (int pin = 0; pin < 2 * PARKING_SPOTS; pin += 2) {

    expander.pinMode(pin, INPUT); //Optical sensors

    expander.pinMode(pin + 1, OUTPUT); //Light indicators

  }

} Serial.begin(115200): This initializes the serial communication, which is useful for debugging by allowing messages to be sent to your computer. expander.begin(SX1509_ADDRESS): This starts communication with the SX1509 I/O expander. If it fails to connect, the program will print an error message and stop. for loop: The loop sets up each parking spot. For each spot: One pin is configured as an input to read data from the optical sensor. The next pin is set as an output to control the LED light that shows whether the spot is available or not. 3. Loop function (runs continuously) void loop() {

  for (int pin = 0; pin < 2 * PARKING_SPOTS; pin += 2) {

    state = expander.digitalRead(pin); //Read Optical sensor

    if (state != space_nr[pin]) {

      if (state == HIGH) {

       Particle.publish("busy", String::format("space nr. %d", space_nr));

       expander.digitalWrite(pin + 1, LOW); //Turn off light

   }

   else {

       Particle.publish("free", String::format("space nr. %d", space_nr));

       expander.digitalWrite(pin + 1, HIGH); //Turn on light

   }

    }

    space_nr[pin] = expander.digitalRead(pin);

  }

} For loop: This loop continuously checks each parking space. For each spot, it does the following: expander.digitalRead(pin): Reads the status of the optical sensor for that parking space. If the sensor detects a car, the state is HIGH (occupied); otherwise, it is LOW (empty). if (state != space_nr[pin]): This checks if the sensor’s reading has changed since the last time it was checked (for example, if a car has parked or left). If the sensor detects a car ( state == HIGH ): Particle.publish(“busy”): Sends a message to the cloud saying the spot is occupied. expander.digitalWrite(pin + 1, LOW): Turns off the LED light, signaling that the spot is taken. If the sensor detects the spot is empty ( state == LOW ): Particle.publish(“free”): Sends a message to the cloud saying the spot is free. expander.digitalWrite(pin + 1, HIGH): Turns on the LED light, indicating the spot is available. space_nr[pin] = expander.digitalRead(pin): Updates the parking space’s current status in the array so the system knows its new state. Cloud integration The cloud integration facilitates real-time updates by transmitting events indicating the status of parking spots. These updates can also be forwarded to a time series database using other means of communication such as MQTT. This setup allows for continuous monitoring and historical analysis of parking spot availability, enabling advanced analytics, predictive maintenance, and optimized parking management strategies. The seamless flow of data ensures efficient and accurate parking solutions, enhancing user experience and operational efficiency. Conclusion Effective parking management plays a key role in improving the overall efficiency, convenience, and sustainability of smart buildings. By incorporating sensors and IoT technology, smart parking systems make it easier to optimize the use of parking spaces, provide real-time updates on availability, and enhance security. These systems not only improve the parking experience by reducing the time spent searching for a spot but also contribute to environmental sustainability by minimizing unnecessary driving, which reduces emissions. The benefits extend beyond just convenience. Smart parking systems streamline operations, reduce costs, and allow for better resource management, all while delivering a smoother, more user-friendly experience. This makes smart parking a crucial component in the design and functionality of modern smart buildings, where innovation, efficiency, and sustainability are increasingly important.

Problem statement Ever wish you had three arms? Picture this: you come home, juggling bags of groceries in both hands, with rain pouring down, and now you have to dig around for your keys without letting everything get soaked. Not ideal, right? Or imagine situations where you want things to just work when your face is detected—like automatically unlocking a medal cabinet when you’re standing in front of it, or switching on a small fan when you sit down at your desk. Solution Enter the facial recognition doorbell and smart unlocking system. This setup could save you from juggling groceries by recognizing your face and unlocking the door as you approach. Plus, it sends you notifications when someone familiar is at the door, or alerts you if an unexpected visitor shows up. With a few tweaks, this same concept can be applied to things like activating a desk fan or other smart actions you can dream up. To build this proof of concept (PoC), I used an M2 SoM Evaluation Board, a B524 SoM, and the Person Sensor from Useful Sensors. The initial goal was a facial recognition doorbell that could signal and send notifications when someone appeared in front of the sensor. From there, I took it a step further—enabling facial identification to not just detect a person, but to recognize who they are. How does it work? From a user perspective, the process is straightforward: The sensor continuously checks for faces in its view. If a face is detected: It checks whether the face matches one of the eight identities it has been calibrated to recognize. If a matching face is found, the Particle device verifies if that person is allowed to unlock the door and signals the servo accordingly. A mobile notification is sent through Pushover, identifying the person detected. Bill of materials MCU: Particle M.2 SoM Evaluation Board B524 , it has cellular and Bluetooth connectivity (no Wi-Fi), but if you want Wi-Fi instead of cellular connectivity, a Photon 2 dev board can be used and is more cost effective Person Sensor by Useful Sensors , priced at ~$10 USD! Optional, but recommended separate power source for the servo or actuator, especially if the latter is power hungry or under load Optional LiPo battery, some options Linear actuator kit , you can replace this with any servo, push rod, or larger linear actuator Qwiic Cable – Grove Adapter (100mm) , this if you want an easy way of connecting the Person Sensor to the Grove port on the M.2 SoM Eval Board, another option is to use separate jumper wires. Skills & tools required For this project, you’ll need A Particle account and basic understanding of the Particle platform’s capabilities. Particle-flavored, Arduino-style, C++ development. No soldering is required for this PoC Optional: 3D-printed case for the Eval Board, and a 3D-printed enclosure for the Person Sensor Assembly Only a few steps are needed to assemble the system (see the top image for a visual overview): Attach the B524 to the Eval Board Connect the cellular antenna to the Eval Board (the Bluetooth antenna can be left unconnected for this project). Connect the Person Sensor to the Eval Board, ensuring that you connect it to the I2C Grove port, not the analog port! Optional: Connect a battery If using a 6V servo or actuator like in this project, it can be powered temporarily from the Eval Board. For long-term use, a separate power source is recommended. In following images following wire colors are used: white = signal, black = ground, red = power Connect the servo signal wire to PWM0 ( D4 in the program) Connect the ground wire to GND on the board Connect the power wire to VCC on the board Power the B524 using the SOM power switch Connect the Eval board to your computer via an USB-cable If using a battery, charge it using the BAT POWER switch Optional: Test the servo You can optionally verify the servo connection using this test program , which moves the servo horn between its two endpoints. The program is optimized for the specific servo used in this project, so verify your servo’s specifications before running it. Software apps and online services Visual Studio Code with the Particle Workbench extension installed Optional Particle’s Webhook Integration for sending notifications to your mobile Twilio, Pushover, or similar services for sending SMS or notifications The complete program can be found here Set up a Webhook integration to Pushover This assumes you are using the Pushover service, but the overall principle is similar, regardless of chosen service. Pushover service Create an account at Pushover (or similar service, e.g. Twilio) Create an application in Pushover Take a note of the User Key and API token Also install the Pushover app on your mobile device to get notifications User key field in Pushover API Token/key in Pushover Particle webhook In the Particle console, Go to Integrations Add a new integration Scroll down and select Custom Webhook Select ´Custom template` Paste in the code below Replace the token and user in the code with the ones from your chosen service event – in this case “face_detected” – should be same event as you are publishing from your code Test the integration, if everything is set up correctly, you should get a notification on your mobile device If you use Pushover, the notification on your mobile is received through the Pushover service, not as a SMS. {
    "name": "Identified as person: ",
    "event": "face_detected",
    "responseTopic": "{{PARTICLE_DEVICE_ID}}/hook-response/{{PARTICLE_EVENT_NAME}}",
    "disabled": false,
    "template": "webhook",
    "url": "https://api.pushover.net/1/messages.json",
    "requestType": "POST",
    "noDefaults": true,
    "rejectUnauthorized": true,
    "unchunked": false,
    "dataUriResponseEvent": false,
    "form": {
        "token": "token to selected service",
        "user": "user id at selected service",
        "title": "Door opened by person ",
        "message": "{{{PARTICLE_EVENT_VALUE}}}"
    }
} Calibrate the Person Sensor The idea with the Person Sensor is that it should behave similarly as any other sensor, i.e. send data back to the calling device. It is pre-programmed with algorithms that detect nearby faces, and return information over a simple I2C interface. It is designed to be used as an input to a larger system and be treated like any other sensor where power and information are provided through the I2C interface. All this means that apart from a few configurations options, the sensor can’t be programmed, which also makes it extremely tamperproof (100 %?). But how do we then get it to not only recognize if a face is seen , but also to identify the face ? The solution here is called calibration. Calibration The calibration can in theory be done stand-alone, but for practical purposes a computer should be connected. This way you can verify the functionality via the terminal window: Position the person whose face you want to store in front of the sensor. When the face is detected, the green LED will light up. Within ~200 ms, press the Mode button on the Eval Board to store the face’s features and assign it an ID in the sensor’s EEPROM. Up to eight faces can be stored, with IDs ranging from 0 to 7. Repeat this process for each new face you want to store. Below the function which is reacting on the button event. The “magic” happens in this code line – person_sensor_write_reg(NEXT_ID_REGISTER, nextFaceID); – which stores the face’s features and corresponding ID into EEPROM. void button_clicked(system_event_t event, int param)
{
    int times = system_button_clicks(param);

    faceIDs[nextFaceID] = nextFaceID;                   // Assign new ID to face
    person_sensor_write_reg(NEXT_ID_REGISTER, nextFaceID);
    Serial.printlnf("******** %d ********", nextFaceID);
    nextFaceID++;
} Mode button Verify facial identification Both during the calibration process and under normal use you can follow what the program is doing via the terminal window. To open this, open the Command Palette (Ctrl+Shift+P) and search for Particle: Serial Monitor . If you want to redo the calibration, just recycle power to the device and start the calibration again. Apart from verification and troubleshooting purposes, you should also take a note of which face is having which ID. E.g. if your face were registered with ID 0, and your childrens with 1 respectively 2, you need to remember this for next step. Set up the facial unlock configuration If you want the servo to react – e.g. open a door – to specific faces, you need to change this code (around line 135): (face-> id == 3 || face -> id == 0) to include the face or faces you want to be able to unlock the door. In this case my own face is registered twice, once with glasses and once without. // opening the door if it's closed and enough time has passed, also publishing to Particle
        unsigned long currentTime = millis();
        if ( (currentTime - lastPublishTime >= publishInterval) && (face-> id == 3 || face -> id == 0) && door_open == false) {
            Particle.publish("face_detected", String(face->id), PRIVATE);
            open();
            Serial.println("** OPENING **");
            door_open = true;
            lastPublishTime = currentTime;
            lastOpenTime = currentTime;

        } Notification settings With the Pushover service you can send 10000 notifications/month for free. Especially while setting up and testing this concept, I could easily consume close to 100 notifications per day. From a quota point of view this was still not an issue, but I got tired of the constant pings on my mobile and smartwatch. Hence I decided to send a notification if at least 10 seconds have gone since previous notification. Furthermore, while you are testing the code, you can comment out the Particle.puhlish... function call. Security notes According to Useful Sensors you shouldn’t rely on the facial identification results as a sole security factor, since it’s not designed to be that accurate. It’s intended for less safety-critical applications like personalizing a user experience automatically, where the cost of mistakes is lower. You of course also needs to consider physical security of the device, and weather-proofing everything as per the location. Real-life solution demonstration In this video you can see how the blue “lock” on the left hand is ensuring no-one can steal my marathon medals. The hinge only unlocks when the sensor sees my face, and in this case automatically locks itself after 10 seconds. At the same time a notification is sent to my phone, informing who is opening the cabinet. This is in this use case useful as I can see if someone, apart from me, is in front of the sensor and perhaps trying to break in. Conclusion This tutorial showed how you can create a facial recognition and identification doorbell/notification device with just a few simple components. Plus, we explored how to adapt it for tasks like unlocking doors or triggering other actions. It was also my first time working with a Particle device on their IoT platform, and while there was a bit of a learning curve at the start, I’m surprised how logical everything is, once I got over the initial hurdle!

Problem Last summer, smoke from Canadian wildfires swept across Canada and the US making it dangerous to breathe outside. Air quality issues have been common during fire season in California for years but this time it wasn’t just in dry areas, it was in most of the United States. This dangerous air was a threat to anyone with lungs but was especially dangerous to asthmatics. Data was available for outdoor air quality in most places, however the air wasn’t just dangerous outdoors. Smoky air made its way inside as well and most people had no way of keeping track of the air quality in their own space. Commercially available products were expensive and sold quickly. Most people just had to hope that their air was fine. Fire season is coming up this year and most people still do not have their own air quality monitoring systems. Solution This tutorial guides you through the process of building a low-cost, portable air quality monitoring system using the Particle Boron microcontroller and a variety of Grove sensors. By following the step-by-step instructions, you’ll integrate sensors for measuring particulate matter, carbon dioxide, volatile organic compounds and more. The device will be programmed using the Particle Workbench to log raw sensor data to Particle Cloud. Then raw data will be translated to human readable meaning status using Particle Logic in Particle Cloud without maintaining the business logic inside firmware. Translated data will be sent to AWS for sending the alert to a Slack channel. Once you have data in AWS, you can do a lot more than just sending a message to Slack, for example, write to a DynamoDB table, build REST API or GraphQL, build and deploy a front end app to visualize the data. Bill of materials Hardware and sensors Things I am using in this projects are: Particle Boron 404X Grove Air Quality Sensor Grove eC02 and VOC Grove Dust Sensor Software Visual Studio Code AWS account Slack account Slack mobile app Set up your Boron First off, go to setup.particle.io and follow the step by step instructions to set up your Boron. In the end, you should see a screen like below. Click on the “Go to Console” button. By now your device should be online. Notice the product you created earlier. Connect the sensors Connect the dust sensor to D4 Connect the air quality sensor to A2 Connect eCO2 & VOC sensor to one of the I2C port From here, click on the “Web IDE” icon from the bottom left menu. Then choose the “Blink An LED” example and flash the firmware. After a few seconds the firmware should get updated and you will notice the led on the board starts blinking. You should also see event data appearing on the Particle Console. Now it’s time to write some custom firmware. Create the project in Workbench Follow the instructions here to set up Particle Workbench and create your project, name it “firmware.” You should see “firmare.cpp” under “src” folder. Let’s fist install necessary libraries. Type cmd + shift + P and type “Particle:Install Library.” It will ask for the library name. Type “SGP30_Gas_Sensor_Grove” and hit enter. Repeat the same process to install following libraries Grove_Air_quality_Sensor JsonParserGeneratorRK Now copy the code ( firmware.cpp ) from my GitHub gist and flash the code. Within a few minutes you should start receiving events in your Particle Cloud console. Particle Logic As you can see the data coming from Boron are raw sensor readings such as air quality=3, eco2=411. These values are not human readable. Would it not be better to say air quality=fresh or pollute? You can perform such translation in the cloud without modifying your firmware code using Particle Logic. Logic is basically a JavaScript function that is triggered when an event is received. We are going to trigger another event after translation, which will in turn post data to the AWS queue. Navigate to the Particle Cloud and select your product. While you are on the products page, click the “Logic” icon from the left menu. In the next page, you will find a few templates, choose “ Reformat JSON data” to customize. On the next page, paste below code in the edit code block. import Particle from 'particle:core';

export default function reformat({ event }) {
  let data;
  try {
    data = JSON.parse(event.eventData);
  } catch (err) {
    console.error("Invalid JSON", event.eventData);
    throw err;
  }

  const reformatted = {
   aq: data.aq === 3 ? "Fresh Air" : data.aq === 2 ? "Low Pollution" : data.aq===1 ? "High Pollution":"Danger",
   eco2: data.eco2 <= 1000? "Normal": data.eco2 <= 2000? "Poor": data.eco2 <= 5000? "Danger":"Extremly Danger",
   tvoc: data.tvoc <=200? "Normal": data.tvoc <=3000? "Little Discomfort": data.tvoc <=25000? "Discomfort":"Toxic",
   dust: data.dustcon <=54? "Good": data.tvoc <=154? "Moderate": data.tvoc <=354 ? "Unhealthy":  "Hazardous"
  };

  Particle.publish("data-reformatted", reformatted, { productId: event.productId });
} Click on ‘Next” and then on the next page, select the product from the drop down and type the same event name you used in the firmware code. Now if you navigate to “Events” page, you will see both the events — one coming from the device and another formatted one from the “logic.” AWS integration Now let’s send the formatted data to AWS Simple Queue Service using Particle Integration. Working knowledge on AWS is required for this part of the tutorial. Setting up an AWS account and getting started is outside of the scope of this tutorial. First create an IAM user called “particle-sqs-user.” Then go to the user detail page and generate an access key and secret. Copy them somewhere secure. You will need them when you will create the integration on the Particle Console. Also keep a note of the user ARN. Next, create a standard queue by navigating to AWS SQS and then under Access Policy, restrict the access to only the user you just created. Paste the ARN in the box, leave all other fields as default and create the queue. Now head over to the Particle Console and navigate to the integration page. Then search for “AWS SQS.” On the next page, enter a name for the integration of your choice. Under the event name, make sure to put the event name you used in your logic function. Under the URL, paste the URL from the AWS SQS console. Expand “Advanced settings,” put the same URL for “QueueUrl” and then paste AWS access key and secrets. Keep everything else as default and enable the integration. Just after a few minutes if you scroll down on the integration page, you will notice the events being sent from the Particle Cloud. Now to confirm if AWS is receiving the messages, head over to the AWS SQS console and you will notice the number of messages available in the queue. Congratulations!!! You have successfully integrated AWS with Particle Cloud. Slack notification The last piece in our puzzle is sending out notification to Slack. For that we will create a lambda function, which will be triggered when a message is received on SQS. First, navigate to the AWS Lambda console and click on the “Create function” button. On the next page, enter “particleAQAS” as the function name, choose Nodejs 20.x as your runtime, leave everything else as default and click on the “Create function” button. Within a few seconds lambda function will be created: Now navigate to Configuration and then Permissions and click on the execution role. It will take you to the IAM role. Click on “Add permissions” and then “Create inline policy.” Then in the policy editor JSON view, paste below policy. Make sure to change the account id. Follow the steps and create the policy. {
    "Version": "2012-10-17",
    "Statement": [
        {
            "Sid": "VisualEditor0",
            "Effect": "Allow",
            "Action": [
                "sqs:DeleteMessage",
                "sqs:ReceiveMessage",
                "sqs:GetQueueAttributes"
            ],
            "Resource": "arn:aws:sqs:us-east-1:ACCUNT_ID:aqas-particle-queue"
        }
    ]
} From there, head over to your lambda function page and click on the “+ Add trigger” button. Then select SQS as trigger and select the queue you created earlier and add the trigger. Now if you go to “Monitor” -> “View CloudWatch Log”, you will notice the logs being generated. Now let’s modify the lambda code to extract sensor data from the message and send notification to Slack. I am assuming you have a Slack webhook URL available with you. Paste below code in your lambda and deploy the function. import * as http from 'https';

const defaultOptions = {
    host: 'hooks.slack.com',
    port: 443,
    headers: {
        'Content-Type': 'application/json',
    }
}

const post = (path, payload) => new Promise((resolve, reject) => {
    const options = { ...defaultOptions, path, method: 'POST' };
    const req = http.request(options, res => {
        let buffer = "";
        res.on('data', chunk => buffer += chunk)
        res.on('end', () => resolve(buffer))
    });
    req.on('error', e => reject(e.message));
    req.write(JSON.stringify(payload));
    req.end();
})

export const handler = async (
  event,
  context
) => {
  console.log('Received event:', JSON.stringify(event, null, 2));
  console.log('Received context:', JSON.stringify(context, null, 2));
  for (const message of event.Records) {
    await processMessageAsync(message);
  }
  console.info('done');
};

async function processMessageAsync(message) {
  try {
    const data = JSON.parse(message.body)
    console.log(data);
    const text = Object.entries(JSON.parse(data.data)).map(([key, value]) => `${key}:${value}`).join("\n");
    await post(process.env.SLACK_WEBHOOK_PATH, { text: text });
  } catch (err) {
    console.error('An error occurred');
    throw err;
  }
} Soon you will start receiving alerts from Slack like below. Display data on Ubidots The bonus: let me show you how to display the data on Ubidots Dashboard. Let’s first modify our Logic function to add raw sensor values to display on the dashboard along with deviceId to bind with the dashboard. const reformatted = {
   aq: data.aq === 3 ? "Fresh Air" : data.aq === 2 ? "Low Pollution" : data.aq===1 ? "High Pollution":"Danger",
   eco2: data.eco2 <= 1000? "Normal": data.eco2 <= 2000? "Poor": data.eco2 <= 5000? "Danger":"Extremly Danger",
   tvoc: data.tvoc <=200? "Normal": data.tvoc <=3000? "Little Discomfort": data.tvoc <=25000? "Discomfort":"Toxic",
   dust: data.dustcon <=54? "Good": data.tvoc <=154? "Moderate": data.tvoc <=354 ? "Unhealthy":  "Hazardous",
