#include "EPD.h"
#include "GUI_Paint.h"
#include <WiFi.h>
#include <WiFiClient.h>

// ===================== USER SETTINGS =====================
#define SCREEN_W 400
#define SCREEN_H 300
#define REFRESH_INTERVAL_MIN 2   // e-ink refresh every 2 minutes

const char* WIFI_SSID = "fahad";
const char* WIFI_PASS = "fahad123";
// =========================================================

UBYTE *BlackImage, *RYImage;
WiFiServer server(80);

float latestTemperature = -100.0;
unsigned long lastUpdateTime = 0;
unsigned long refreshInterval = REFRESH_INTERVAL_MIN * 60 * 1000UL;

// =========================================================

void setup() {
  USBSerial.begin(115200);
  USBSerial.println("ESP32-S3 E-Ink Text Receiver Starting...");

  DEV_Module_Init();
  eink_init();

  // Wi-Fi setup
  WiFi.mode(WIFI_STA);
  WiFi.begin(WIFI_SSID, WIFI_PASS);
  USBSerial.print("Connecting to WiFi");
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    USBSerial.print(".");
  }
  USBSerial.println();
  USBSerial.print("Connected! IP: ");
  USBSerial.println(WiFi.localIP());

  server.begin();
  displayText("Waiting for Data...");
  lastUpdateTime = millis();
}

// =========================================================

void loop() {
  WiFiClient client = server.available();

  if (client) {
    USBSerial.println("Client connected!");
    String requestData = "";

    while (client.connected()) {
      while (client.available()) {
        char c = client.read();
        if (c == '\n') {

          // Save latest received value (but DO NOT refresh display yet)
          latestTemperature = requestData.toFloat();
          USBSerial.print("Received: ");
          USBSerial.println(latestTemperature);
          client.println("ACK");
          client.stop();
          break;

        } else {
          requestData += c;
        }
      }
    }
  }

  // === REFRESH EVERY 3 MINUTES ONLY ===
  if (millis() - lastUpdateTime >= refreshInterval) {
    USBSerial.println("2-minute refresh triggered.");
    updateDisplay(latestTemperature);
    lastUpdateTime = millis();
  }
}

// ============================================================
// ================= DISPLAY INITIALIZATION ===================
void eink_init() {
  USBSerial.println("E-Ink Init...");
  EPD_4IN2B_V2_Init();
  EPD_4IN2B_V2_Clear();
  delay(500);

  long Imagesize = SCREEN_W * SCREEN_H / 8;
  BlackImage = (UBYTE *)malloc(Imagesize);
  RYImage = (UBYTE *)malloc(Imagesize);

  Paint_NewImage(BlackImage, SCREEN_W, SCREEN_H, 0, WHITE);
  Paint_NewImage(RYImage, SCREEN_W, SCREEN_H, 0, WHITE);
}

// ============================================================
// ================= DISPLAY FUNCTIONS ========================
void displayText(String message) {
  Paint_SelectImage(BlackImage);
  Paint_Clear(WHITE);
  Paint_SelectImage(RYImage);
  Paint_Clear(WHITE);

  // Title (red)
  Paint_SelectImage(RYImage);
  Paint_DrawString_EN(45, 80, "ESP32S3 RECEIVER", &Font24, WHITE, RED);

  // Value (black)
  Paint_SelectImage(BlackImage);
  Paint_DrawString_EN(50, 150, message.c_str(), &Font24, BLACK, WHITE);

  EPD_4IN2B_V2_Display(BlackImage, RYImage);
  delay(2000);
}

void updateDisplay(float temp) {
  char msg[64];
  if (temp < -50) sprintf(msg, "No Data");
  else sprintf(msg, "Temperature: %.2f C", temp);

  EPD_4IN2B_V2_Init();    // wake display
  displayText(String(msg));
  EPD_4IN2B_V2_Sleep();   // sleep to save power
